  console.log('[神速Down] backend =', HKLIST_URL)

let _hklistNeedPwd = null

  let _hklistMaxOnce = 5
  function _hklistGet(url) {
    return new Promise((resolve) => {
      try {
        GM_xmlhttpRequest({
          method: 'GET', url, timeout: 5000,
          onload: (r) => resolve(r), onerror: () => resolve(null), ontimeout: () => resolve(null),
        })
      } catch (_) { resolve(null) }
    })
  }
  async function ensureHklistConfig() {
    if (_hklistNeedPwd !== null) return _hklistNeedPwd
    const r = await _hklistGet(`${HKLIST_URL}/api/v1/user/parse/config?token=guest`)
    try {
      const j = r && r.responseText ? JSON.parse(r.responseText) : null
      _hklistNeedPwd = !!(j && j.data && j.data.need_password)
      const mo = j && j.data && Number(j.data.max_once)
      if (mo && mo > 0) _hklistMaxOnce = mo
    } catch (_) { _hklistNeedPwd = false }
    return _hklistNeedPwd
  }
  function buildHklistAuth() {
    const pw = (typeof getPassword === 'function' ? getPassword() : (localStorage.password ?? null)) || ''
    // token 一律送 'guest' 占位:
    // - 用户填 admin 全局门票 → 后端 PassFilter 直通 + Controller 自动清空 token
    // - 用户填真卡密 → PassFilter merge 自动把卡密注入 request[token], 覆盖 'guest'
    // 之前 token: pw||'guest' 会把 admin 当卡密塞 token 字段, 后端 Token 表查不到 admin → "卡密不存在"
    return { parse_password: pw, token: 'guest' }
  }

  ensureHklistConfig()
