let _versionBlocked = false
  let _saltReady = false
  let _saltReadyCallbacks = []
  function _onSaltReady(cb) {
    if (_saltReady) return cb()
    _saltReadyCallbacks.push(cb)
  }
  function _resolveSalt() {
    _saltReady = true
    _saltReadyCallbacks.forEach(cb => cb())
    _saltReadyCallbacks = []
  }
  function checkScriptVersion() { return _checkScriptVersionAsync() }
  // Promise 版本: 调用方 await 后可立刻读 _versionBlocked, 用于按钮 click 实时拦截.
  // 同步对齐后端 force_update + min_version, 不再依赖 boot 一次性结果.
  // 缓存最近一次 server 返的 info, 给 click handler 弹更新窗时复用 latest_version/update_url.
  let _lastVersionInfo = null
  function _checkScriptVersionAsync() {
    return new Promise(function (resolve) {
      // 全兜底: timeout/onerror/onabort/ontimeout 任何一种状态都必须 resolve,
      // 否则按钮 click handler await 会永久 pending 导致"按钮无反应".
      var done = false
      var _done = function () { if (!done) { done = true; resolve() } }
      setTimeout(_done, 1500)
      try {
        GM_xmlhttpRequest({
          method: 'GET',
          url: `${HKLIST_URL}/api/v1/parse/version`,
          headers: { 'Accept': 'application/json' },
          timeout: 1500,
          onload: function (res) {
            try {
              const json = JSON.parse(res.responseText)
              if (json.code === 200 && json.data) {
                const info = json.data
                _lastVersionInfo = info
                if (info.salt) _versionSalt = info.salt
                _resolveSalt()
                // force_update + 本地版本低于后端 min_version → 只标记 blocked, 不主动弹窗;
                // 弹窗由 click handler 同步触发, 避免 boot 自动弹 + click 重弹的双重弹窗.
                if (info.force_update && compareVersion(version, info.min_version) < 0) {
                  _versionBlocked = true
                }
              } else { _resolveSalt() }
            } catch (e) { _resolveSalt() }
            _done()
          },
          onerror: function () { _resolveSalt(); _done() },
          ontimeout: function () { _resolveSalt(); _done() },
          onabort: function () { _resolveSalt(); _done() },
        })
      } catch (e) { _resolveSalt(); _done() }
    })
  }
  function compareVersion(v1, v2) {
    var a = v1.split('.').map(Number), b = v2.split('.').map(Number)
    for (var i = 0; i < Math.max(a.length, b.length); i++) {
      var n1 = a[i] || 0, n2 = b[i] || 0
      if (n1 < n2) return -1
      if (n1 > n2) return 1
    }
    return 0
  }
