  ;(function _hookThunderFetch() {
    if (location.hostname !== 'pan.xunlei.com') return
    if (typeof unsafeWindow === 'undefined' || !unsafeWindow.fetch) return
    if (unsafeWindow._thunderHooked) return
    unsafeWindow._thunderHooked = true
    unsafeWindow._thunderListCtx = null
    unsafeWindow._thunderListCache = {}
    var origFetch = unsafeWindow.fetch
    unsafeWindow.fetch = function (input, init) {
      var url = (typeof input === 'string') ? input : (input && input.url) || ''
      var p = origFetch.apply(this, arguments)

      if (/(\/files|\/share)(\?|\/|$)/i.test(url) && /xunlei/i.test(url)) {
        unsafeWindow._thunderListCtx = { url: url, init: init || {} }
        try {
          p.then(function (res) {
            if (!res || !res.ok) return
            var clone = res.clone()
            clone.json().then(function (j) {
              try {
                var files = (j && (j.files || (j.data && j.data.files))) || []
                var u = new URL(url, location.origin)
                var parentId = u.searchParams.get('parent_id') || u.searchParams.get('pdir_fid') || ''
                if (parentId && files.length >= 0) {
                  unsafeWindow._thunderListCache[parentId] = files
                  console.log('[神速Down] hook 缓存 ' + files.length + ' files parent=' + parentId)
                }
              } catch (_) {}
            }).catch(function () {})
          }).catch(function () {})
        } catch (_) {}
      }
      return p
    }
    console.log('[神速Down] thunder fetch hook installed')
  })()

  async function _thunderListFolderChildren(folderFid) {
    if (typeof unsafeWindow === 'undefined') return []
    if (unsafeWindow._thunderListCache && unsafeWindow._thunderListCache[folderFid]) {
      var cached = unsafeWindow._thunderListCache[folderFid]
      console.log('[神速Down] thunder ' + folderFid + ' cache hit, ' + cached.length + ' files')
      return cached
    }
    var ctx = unsafeWindow._thunderListCtx
    if (!ctx) {
      console.warn('[神速Down] thunder list ctx 未就位 (SPA 没发过 list)')
      return []
    }
    try {
      var newUrl = ctx.url
      if (/parent_id=/.test(newUrl)) {
        newUrl = newUrl.replace(/parent_id=[^&]*/, 'parent_id=' + encodeURIComponent(folderFid))
      } else {
        newUrl += (newUrl.indexOf('?') < 0 ? '?' : '&') + 'parent_id=' + encodeURIComponent(folderFid)
      }
      var res = await unsafeWindow.fetch(newUrl, {
        method: 'GET',
        credentials: 'include',
        headers: (ctx.init && ctx.init.headers) || {},
      })
      if (!res.ok) { console.warn('[神速Down] thunder folder fetch ' + res.status); return [] }
      var j = await res.json()
      var files = (j && (j.files || (j.data && j.data.files))) || []
      unsafeWindow._thunderListCache[folderFid] = files
      console.log('[神速Down] thunder ' + folderFid + ' fetched ' + files.length + ' files')
      return files
    } catch (e) { console.warn('[神速Down] thunder folder fetch error', e); return [] }
  }

  async function _thunderExpandFolder(folderFid, depth, ctx) {
    if (!ctx) ctx = { count: 0, max: 200 }
    if (depth > 4 || ctx.count >= ctx.max) return []
    var children = await _thunderListFolderChildren(folderFid)
    var out = []
    for (var i = 0; i < children.length; i++) {
      if (ctx.count >= ctx.max) break
      var f = children[i]
      var fid = f.id || f.file_id || f.fid
      if (!fid) continue
      var name = f.name || f.file_name || ''
      var kind = String(f.kind || f.type || '')
      var isDir = /folder|dir/i.test(kind) || f.is_folder === true
      if (isDir) {
        var sub = await _thunderExpandFolder(fid, depth + 1, ctx)
        out = out.concat(sub)
      } else {
        out.push({ fid: fid, file_name: name, size: parseInt(f.size || 0, 10) || 0, dir: false })
        ctx.count++
      }
    }
    return out
  }

