  async function sendAria2() {
    layer.load(2, {
      shade: [0.3, '#FFF'],
    })

    let rpcDir = $('#dialogTxtSavePath').val().replace(/\\/g, '/')
    let rpcHostUrl = $('#dialogAriaRPC').val()
    let rpcToken = $('#dialogAriaToken').val()

    if (!rpcHostUrl) {

      rpcHostUrl = 'http://localhost:16800/jsonrpc'
    }

var _validLinks = (links || []).filter(function (l) { return l && typeof l.url === 'string' && l.url.length > 0 })
    console.log('[神速Down] sendAria2 links 总数=' + (links || []).length + ' 有效=' + _validLinks.length, 'sample=', (links && links[0]) || null)
    if (_validLinks.length === 0) {
      layer.closeAll('loading')
      $('#loadingtext').hide()
      var _backendMsg = ''
      for (var _i = 0; _i < (links || []).length; _i++) {
        if (links[_i] && links[_i].message) { _backendMsg = links[_i].message; break }
      }
      Swal.fire({
        title: '推送失败',
        html: '<div style="text-align:left">' + (_backendMsg || '下载链接为空,请重新解析') + '</div>',
        icon: 'error',
      })
      return
    }

    try {
      const results = await Promise.all(_validLinks.map((link) => {
        return new Promise((resolve) => {
          GM_xmlhttpRequest({
            method: 'POST',
            responseType: 'json',
            timeout: 5000,
            url: rpcHostUrl,
            data: JSON.stringify({
              id: 'shensuDown',
              jsonrpc: '2.0',
              method: 'aria2.addUri',
              params: [
                ...(rpcToken ? [`token:${rpcToken}`] : []),
                [link.url],
                (() => {
                  const headers = []
                  if (link.ua) headers.push(`User-Agent: ${link.ua}`)
                  if (link.referer) headers.push(`Referer: ${link.referer}`)
                  if (link.cdn_host) headers.push(`Host: ${link.cdn_host}`)
                  var fileDir = rpcDir
                  if (link.subdir) {
                    fileDir = rpcDir + '/' + link.subdir
                  }
                  return {
                    'max-connection-per-server': '16',
                    split: '16',
                    'min-split-size': '4M',
                    'allow-overwrite': 'true',
                    dir: fileDir,
                    out: link.filename,
                    header: headers,
                    'check-certificate': 'false',
                  }
                })(),
              ],
            }),
            onload: function (res) {
              var json = res.response
              if (typeof json === 'string') { try { json = JSON.parse(json) } catch(e) { json = null } }
              console.log('[神速Down] aria2/motrix RPC status=' + res.status, 'body=', json || res.response)
              if (res.status === 200 && json) {
                if (json.error) {
                  resolve({ ok: false, msg: json.error.message === 'Unauthorized'
                    ? 'RPC 授权失败: Token 不正确,检查 Aria2/Motrix 的 RPC 密钥与脚本面板里填的是否一致'
                    : '推送失败: ' + (json.error.message || JSON.stringify(json.error)) })
                } else if (json.result) {
                  resolve({ ok: true })
                } else {
                  resolve({ ok: false, msg: 'RPC 响应无 result 字段: ' + JSON.stringify(json).slice(0, 300) })
                }
              } else if (res.status === 401 || res.status === 403) {
                resolve({ ok: false, msg: 'RPC 授权失败 (HTTP ' + res.status + '): 在 Aria2/Motrix 设置里有 RPC 密钥(secret),请填到脚本面板的 Token 输入框' })
              } else if (res.status === 404) {
                resolve({ ok: false, msg: 'RPC 路径不存在 (HTTP 404,当前: ' + rpcHostUrl + '): 检查路径,Aria2/Motrix 默认是 /jsonrpc' })
              } else {
                resolve({ ok: false, msg: 'RPC 响应异常 (HTTP ' + (res.status || '0') + ',当前: ' + rpcHostUrl + '): ' +
                  (typeof res.response === 'string' ? res.response.slice(0, 300) : JSON.stringify(res.response).slice(0, 300)) })
              }
            },
            ontimeout: () => {
              resolve({ ok: false, msg: '连接 RPC 服务器超时: 检查 Aria2/Motrix 是否正在运行 (当前: ' + rpcHostUrl + ')' })
            },
            onerror: (res) => {
              resolve({ ok: false, msg: '连接 RPC 服务器失败: 检查 Aria2/Motrix 是否正在运行 (当前: ' + rpcHostUrl + ')' })
            },
          })
        })
      }))

      $('#loadingtext').hide()
      layer.closeAll('loading')

      const failed = results.filter(r => !r.ok)
      if (failed.length > 0) {
        Swal.fire({
          title: '系统提示',
          html: failed[0].msg,
          icon: 'error',
        })
      } else {
        await refreshAds()
        Swal.fire({
          title: '系统提示',
          html: `推送成功！快去看看吧 若下载失败请检查保存文件路径有无配置，关闭您的代理下载！<br>${SCONFIG.config.ad_push}`,
          icon: 'success',
        })
      }
    } catch (error) {
      $('#loadingtext').hide()
      layer.closeAll('loading')
      console.log(error)
      Swal.fire({
        title: '系统提示',
        html: '发生错误,请刷新页面重试！',
        icon: 'error',
      })
    }
  }

let _quarkListData = null
  let _quarkSelectedFiles = []
  let _quarkDriveFiles = []
  let _quarkTempShareId = null
  let _quarkUserSelected = []
  let _thunderPrefetchPromise = null
  let _thunderPrefetchUrl = ''

  function getQuarkSelectedFiles() {
    var selected = []
    var seen = {}

var rows = document.querySelectorAll(
      'tr.ant-table-row-selected[data-row-key], ' +
      'tr.ant-table-row[class*="-selected"][data-row-key]'
    )
    rows.forEach(function (tr) {
      var fid = tr.getAttribute('data-row-key')
      if (!fid || seen[fid]) return
      seen[fid] = 1
      var nameEl = tr.querySelector('.filename-text')
      var name = (nameEl && (nameEl.getAttribute('title') || nameEl.textContent)) || ''
      selected.push({ fid: fid, file_name: name.trim(), size: 0, dir: false })
    })

var thunderItems = document.querySelectorAll(
      'li[class*="SourceListItem__item"]:has(input[type="checkbox"]:checked)'
    )
    if (thunderItems.length > 0) {
      selected._thunderProbed = true

      var fiberOk = true
      var fiberPicked = []
      thunderItems.forEach(function (li) {
        if (!fiberOk) return

        var f = _searchFileInThunderFiber(li)
        if (!f || !f.fid) { fiberOk = false; return }
        if (!seen[f.fid]) { seen[f.fid] = 1; fiberPicked.push(f) }
      })
      if (fiberOk && fiberPicked.length > 0) {
        fiberPicked.forEach(function (f) { selected.push(f) })
        selected._fromFiber = true
        console.log('[神速Down] ⚡⚡ fiber 抽到 ' + fiberPicked.length + ' 文件 (跳过 后端 list)')
      } else {

        function _norm(s) { return String(s || '').replace(/\s+/g, '').toLowerCase() }
        var nameToFid = {}
        if (typeof _quarkListData !== 'undefined' && _quarkListData && Array.isArray(_quarkListData.list)) {
          _quarkListData.list.forEach(function (f) {
            if (f && f.file_name) nameToFid[_norm(f.file_name)] = {
              fid: f.fid, dir: !!f.dir, size: f.size || 0, raw: f.file_name,
              share_fid_token: f.share_fid_token || ''
            }
          })
        }
        var missed = []
        thunderItems.forEach(function (li) {
          var titleEl = li.querySelector('a[title], .SourceListItem__name a, .highlight-text')
          var name = titleEl ? (titleEl.getAttribute('title') || titleEl.textContent || '').trim() : ''
          if (!name) return
          var hit = nameToFid[_norm(name)]
          if (hit && !seen[hit.fid]) {
            seen[hit.fid] = 1
            selected.push({ fid: hit.fid, file_name: hit.raw, size: hit.size, dir: hit.dir, share_fid_token: hit.share_fid_token })
          } else if (!hit) missed.push(name)
        })
        if (missed.length > 0) console.warn('[神速Down] fiber miss + name 反查 miss:', missed,
          '可用 file_name keys (前5):', Object.keys(nameToFid).slice(0, 5))
      }
    }

    console.log('[神速Down] 探测勾选: quark rows=' + rows.length + ' thunder items=' + thunderItems.length + ' 提取 ' + selected.length + ' 个 fid' + (selected._fromFiber ? ' [via fiber]' : ''))
    return selected
  }

function _searchFileInThunderFiber(li) {
    if (!li) return null
    var hops = 0

var fiberKey = Object.keys(li).find(function (k) {
      return k.indexOf('__reactFiber$') === 0 || k.indexOf('__reactInternalInstance$') === 0
    })
    if (fiberKey) {
      var node = li[fiberKey]
      while (node && hops < 20) {
        var pools = []
        if (node.memoizedProps) pools.push(node.memoizedProps)
        if (node.pendingProps && node.pendingProps !== node.memoizedProps) pools.push(node.pendingProps)
        if (node.memoizedState) pools.push(node.memoizedState)
        if (node.stateNode && typeof node.stateNode === 'object' && node.stateNode !== null) {
          try {
            if (node.stateNode.props) pools.push(node.stateNode.props)
            if (node.stateNode.state) pools.push(node.stateNode.state)
          } catch (_) {}
        }
        for (var i = 0; i < pools.length; i++) {
          var hit = _bfsForThunderFile(pools[i], 0, new WeakSet())
          if (hit) return hit
        }
        node = node.return
        hops++
      }
      return null
    }

var vm = li.__vue__ || li.__vueParentComponent
    if (vm) {
      while (vm && hops < 20) {
        var pools2 = []

        if (vm.$props) pools2.push(vm.$props)
        if (vm.$data)  pools2.push(vm.$data)
        if (vm.$attrs) pools2.push(vm.$attrs)

        if (vm.props && !vm.$props) pools2.push(vm.props)
        if (vm.data && !vm.$data)   pools2.push(vm.data)
        if (vm.setupState) pools2.push(vm.setupState)
        if (vm.ctx) {
          try { pools2.push(vm.ctx) } catch (_) {}
        }
        if (vm.proxy) {
          try {

            if (vm.proxy.$props) pools2.push(vm.proxy.$props)
            if (vm.proxy.$data)  pools2.push(vm.proxy.$data)
          } catch (_) {}
        }
        for (var j = 0; j < pools2.length; j++) {
          var hit2 = _bfsForThunderFile(pools2[j], 0, new WeakSet())
          if (hit2) return hit2
        }
        vm = vm.$parent || vm.parent
        hops++
      }
    }

    return null
  }
  function _bfsForThunderFile(obj, depth, seen) {
    if (!obj || typeof obj !== 'object' || depth > 8) return null
    try { if (seen.has(obj)) return null; seen.add(obj) } catch (_) { return null }

    var keys
    try { keys = Object.keys(obj) } catch (_) { return null }

    var nameField = obj.name || obj.file_name || obj.fileName || obj.title
    var idField   = obj.id || obj.file_id || obj.fid || obj.fileId
    if (typeof nameField === 'string' && nameField.length > 0 &&
        typeof idField === 'string' && idField.length >= 8) {
      var token = obj.share_fid_token || obj.shareFidToken || obj.fid_token ||
                  obj.fidToken || obj.fileToken || obj.file_token || obj.token || ''
      var size  = parseInt(obj.size || obj.file_size || obj.fileSize || 0, 10) || 0
      var kind  = String(obj.kind || obj.type || obj.fileType || '')
      var dir   = /folder|dir/i.test(kind) || obj.is_folder === true || obj.isFolder === true
      console.log('[神速Down] fiber 命中 file:', { fid: idField, name: nameField, size: size, dir: dir, hasToken: !!token })
      return { fid: idField, file_name: nameField, share_fid_token: String(token || ''), size: size, dir: !!dir }
    }

    for (var j = 0; j < keys.length; j++) {
      var k = keys[j]
      if (k === 'return' || k === 'sibling' || k === 'child' || k === 'alternate' ||
          k === 'stateNode' || k === '_owner' || k === '_store' ||
          k === 'firstEffect' || k === 'lastEffect' || k === 'nextEffect' ||
          k === 'updateQueue' || k === 'dependencies') continue
      var vv = obj[k]
      if (vv && typeof vv === 'object') {
        var hit = _bfsForThunderFile(vv, depth + 1, seen)
        if (hit) return hit
      }
    }
    return null
  }

