  // 函数源码 md5 当 fp, 比 length 抗碰撞且任何字符改动都让 fp 变化.
  // (length 方案下函数体加注释/空格不变 fp; md5 方案下一字符差即 fp 完全不同)
  function _funcFp(fn) { return _scriptMd5(String(fn.toString())) }

  function quarkVersionParams() {
    var fp = _funcFp(getQuarkDownloadLinks)
    return {
      script_version: version,
      code_fingerprint: fp,
      version_token: _scriptMd5(version + fp + _versionSalt),
    }
  }

  function _formatErr(err) {
    if (!err) return '未知错误'
    if (err instanceof Error) return err.message || String(err)
    if (typeof err === 'string') return err
    if (err.message) return err.message
    if (err.status === 0 || err.readyState === 0) return '网络错误 (无法连接到后端,请检查后端服务状态)'
    if (err.status) return 'HTTP ' + err.status + (err.statusText ? ' ' + err.statusText : '')
    if (err.error) return String(err.error)
    if (err.finalUrl) return '请求 ' + err.finalUrl + ' 失败'
    try { return JSON.stringify(err) } catch (_) { return String(err) }
  }
  function _shortName(s, maxChars, ellipsis) {
    var arr = Array.from(String(s || ''))
    return arr.length > maxChars ? arr.slice(0, maxChars).join('') + (ellipsis || '..') : arr.join('')
  }
  function formatCurname(files, getName) {
    var n = files.length
    if (n === 0) return ''
    if (n === 1) return _shortName(getName(files[0]), 20, '...')
    var head = files.slice(0, 3).map(function (f) { return _shortName(getName(f), 5) }).join('、')
    return n > 2 ? head + '（共' + n + '个文件）' : head
  }

  function showQuarkFileNames(files) {
    $('#curname').text(formatCurname(files, function (f) { return f.file_name }))
  }

