          listEl.addEventListener('click', function (e) { var card = e.target.closest('.hklist-res-card'); if (!card) return; reportClick(parseInt(card.getAttribute('data-res-id'), 10)); window.open(card.getAttribute('data-res-url'), '_blank') })
          listEl.addEventListener('mouseover', function (e) { var card = e.target.closest('.hklist-res-card'); if (card) { card.style.boxShadow = '0 3px 10px rgba(0,0,0,.15)'; card.style.borderColor = '#2196f3' } })
          listEl.addEventListener('mouseout', function (e) { var card = e.target.closest('.hklist-res-card'); if (card) { card.style.boxShadow = '0 1px 4px rgba(0,0,0,.08)'; card.style.borderColor = '#e6e6e6' } })

