                var _picked = _quarkListData.list.filter(function (f) { return _fidSet[f.fid] && !f.dir })
                if (_picked.length > 0) {
                  _quarkSelectedFiles = _picked
                  showQuarkFileNames(_picked)
                  console.log('[神速Down] (后台) walk 完成,刷新 panel 显示 ' + _picked.length + ' 文件')
                }
